import{_ as s,C as a,o as h,c as u,j as t,a as i,E as n,a3 as c}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"帛书第2章 得一","description":"帛书德篇第2章 · 得一（通行本第39章）","frontmatter":{"title":"帛书第2章 得一","description":"帛书德篇第2章 · 得一（通行本第39章）","category":"guide","aliases":["帛书第2章","马王堆老子2","通行本第39章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/texts/dao-de-jing-boshu/chapter-02.md","filePath":"daoism/texts/dao-de-jing-boshu/chapter-02.md","lastUpdated":1778755688000}'),m={name:"daoism/texts/dao-de-jing-boshu/chapter-02.md"};function p(x,e,g,b,_,f){const o=a("DaoReadingPrelude"),r=a("DaoOriginalReading"),d=a("DaoLineGuide"),l=a("DaoKeywordCards");return h(),u("div",null,[e[0]||(e[0]=t("h1",{id:"帛书老子第2章",tabindex:"-1"},[i("帛书老子第2章 "),t("a",{class:"header-anchor",href:"#帛书老子第2章","aria-label":'Permalink to "帛书老子第2章"'},"​")],-1)),n(o,{title:"第2章 得一",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第39章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第2章"},{label:"对照",text:"通行本第39章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),e[1]||(e[1]=t("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),t("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(r,{paragraphs:["昔之得一者","天得一以清 地得一以宁,","神得一以霝 浴得一以盈","侯王得一以为天下正","亓致之也","谓天毋已清将恐裂","谓地毋已宁将恐发","谓神毋已霝将恐歇","谓浴毋已盈将恐竭","谓侯王毋已贵以高将恐蹶","故必贵而以贱为本","必高矣而以下为基","夫是以侯王自谓曰孤","寡 不榖 此亓贱之为本与 非也","故致数与无与","是故不欲禄禄若玉 硌硌若石"]}),n(d,{lines:[{text:"昔之得一者",tone:"起",guide:"自古以来得到「一」（道的统一性）的——「一」是道的别名，万物得道则各正其命。"},{text:"天得一以清 地得一以宁",tone:"承",guide:"天得一道则清朗，地得一道则安宁——天地因得道而各正其位。"},{text:"神得一以霝 浴得一以盈",tone:"承",guide:"神得道则灵妙，山谷得道则充盈。帛书「霝」通「灵」，「浴」通「谷」——保留古字写法。"},{text:"侯王得一以为天下正",tone:"承",guide:"侯王得道则成为天下的准则与标准——「正」即准则，得道者自然为天下所归。"},{text:"亓致之也",tone:"转",guide:"推而言之——以下反过来论证失道的后果。帛书「亓」通「其」。"},{text:"谓天毋已清将恐裂",tone:"反",guide:"天若不再保持清朗，恐怕就要崩裂——得道则清，失道则裂。"},{text:"谓地毋已宁将恐发",tone:"反",guide:"地若不再保持安宁，恐怕就要爆发——得道则宁，失道则发。"},{text:"谓神毋已霝将恐歇",tone:"反",guide:"神若不再灵妙，恐怕就要停歇——得道则灵，失道则歇。"},{text:"谓浴毋已盈将恐竭",tone:"反",guide:"山谷若不再充盈，恐怕就要枯竭——得道则盈，失道则竭。"},{text:"谓侯王毋已贵以高将恐蹶",tone:"反",guide:"侯王若不再高贵，恐怕就要跌倒——「蹶」即颠覆、垮台，富贵离开了道的根基则危。"},{text:"故必贵而以贱为本",tone:"理",guide:"所以高贵必须以卑贱为根本——贵不离开贱，就像王不离开民，道不离开朴。"},{text:"必高矣而以下为基",tone:"理",guide:"高大必须以低下为基础——越高越要往下扎根，这是老子的「反向思维」。"},{text:"夫是以侯王自谓曰孤 寡 不榖 此亓贱之为本与 非也",tone:"问",guide:"所以侯王自称孤、寡、不榖（谷）——这不就是以贱为本吗？帛书「榖」通「谷」，不榖为君王自谦之称。"},{text:"故致数与无与",tone:"断",guide:"所以最高的荣誉就是没有荣誉——不需要被称赞，这才是真正的荣誉。"},{text:"是故不欲禄禄若玉 硌硌若石",tone:"收",guide:"所以不希望像美玉那样华丽珍贵（禄禄），宁愿像石头那样朴素坚实（硌硌）。华丽引祸，朴素久安。"}]}),e[2]||(e[2]=t("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),t("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(l,{items:[{term:"得一",pinyin:["dé","yī"],meaning:"得到「一」，一即道的统一性。天得一而清，地得一而宁——万物因得道而各正其位。本章围绕「得一」展开正反论证。",context:"昔之得一者——自古得道者皆如此。"},{term:"霝",pinyin:["líng"],meaning:"通「灵」——灵妙、神通。神得一以霝——神得道则灵妙。",context:"帛书用此古字，通行本作「灵」。"},{term:"浴",pinyin:["yù"],meaning:"通「谷」——山谷。浴得一以盈——山谷得道则充盈。",context:"帛书常以「浴」为「谷」。"},{term:"蹶",pinyin:["jué"],meaning:"跌倒、颠覆、垮台。侯王毋已贵以高将恐蹶——离开了谦下的根基，再高的地位也会崩塌。",context:"与「得一」形成对照：得道则安，失道则蹶。"},{term:"榖",pinyin:["gǔ"],meaning:"通「谷」，善、好的意思。不榖为古代君王自谦之称，意为「不善之人」。",context:"侯王自称孤、寡、不榖，正是以贱为本的体现。"},{term:"亓",pinyin:["qí"],meaning:"帛书古字，通「其」。全书通用。",context:"通行本全作「其」。"},{term:"禄禄",pinyin:["lù","lù"],meaning:"华丽珍贵的样子。不欲禄禄若玉——不希望像美玉那样华丽珍贵。",context:"与「硌硌若石」形成对比：宁可朴素坚实，不要华丽引祸。"},{term:"硌硌",pinyin:["luò","luò"],meaning:"石头坚硬朴实的样子。硌硌若石——像石头一样朴素坚实。",context:"老子主张「处其实不居其华」，本章以玉石之喻收束全篇。"}]}),e[3]||(e[3]=c("",13))])}const y=s(m,[["render",p]]);export{q as __pageData,y as default};
